import{_ as p,c as t,o as e,d as s}from"./app.0d14d0b2.js";var o="/assets/kiln.4d6b73dd.jpg";const T='{"title":"TIS","description":"","frontmatter":{"title":"TIS","subtitle":"\u041C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u0430\u044F \u043A\u0435\u0440\u0430\u043C\u0438\u043A\u0438","date":"2015-04-06","icon":"logo.png","cover":"ceramics.jpg","instagram":"tis.ceramics","vk":"tis.ceramics","address":"\u041C\u0430\u043B\u044B\u0439 \u0425\u0430\u0440\u0438\u0442\u043E\u043D\u044C\u0435\u0432\u0441\u043A\u0438\u0439 \u043F\u0435\u0440\u0435\u0443\u043B\u043E\u043A, 4","place":"\u043C. \u0427\u0438\u0441\u0442\u044B\u0435 \u043F\u0440\u0443\u0434\u044B","city":"\u0433. \u041C\u043E\u0441\u043A\u0432\u0430","coord":[55.76709860766733,37.643866385362465],"youtube":"https://youtu.be/Ki_-ruOS5wU","status":"open"},"headers":[],"relativePath":"workshop/catalog/tis/index.md"}',r={},a=s('<p><strong>\u041E\u0411\u0423\u0427\u0415\u041D\u0418\u0415 \u0418 \u041C\u0410\u0421\u0422\u0415\u0420-\u041A\u041B\u0410\u0421\u0421\u042B</strong></p><p><em>\u0413\u043E\u043D\u0447\u0430\u0440\u043D\u043E\u0435 \u0434\u0435\u043B\u043E, \u0434\u0435\u043A\u043E\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043A\u0435\u0440\u0430\u043C\u0438\u043A\u0438 (\u0437\u0430\u043D\u044F\u0442\u0438\u044F \u0432 \u043C\u0438\u043D\u0438-\u0433\u0440\u0443\u043F\u043F\u0430\u0445 \u0434\u043E 4-\u0445 \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u043E \u0441 12.00 \u0434\u043E 23.00), \u0437\u0430\u043F\u0438\u0441\u044C \u043F\u043E \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0443:</em></p><p>\u0412\u0437\u0440\u043E\u0441\u043B\u044B\u0435 - 1400 \u0440\u0443\u0431./1 \u0430\u043A.\u0447\u0430\u0441.</p><p>\u0414\u0435\u0442\u0438 (3-12 \u043B\u0435\u0442) - 1100 \u0440\u0443\u0431./1 \u0430\u043A.\u0447\u0430\u0441. (\u0434\u0435\u0442\u0438 \u0434\u043E 5 \u043B\u0435\u0442 \u0437\u0430\u043D\u0438\u043C\u0430\u044E\u0442\u0441\u044F \u0432 \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u0440\u043E\u0434\u0438\u0442\u0435\u043B\u0435\u0439).</p><p>\u0415\u0441\u043B\u0438 \u0412\u044B \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442\u0435 \u0433\u0440\u0443\u043F\u043F\u043E\u0439 (2-4 \u0447\u0435\u043B.) \u0434\u043B\u044F \u0412\u0430\u0441 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \xAB\u0441\u0435\u043C\u0435\u0439\u043D\u044B\u0439 \u0442\u0430\u0440\u0438\u0444\xBB - \u0441\u043A\u0438\u0434\u043A\u0430 10%.</p><p>\u041F\u0440\u0438 \u043E\u043F\u043B\u0430\u0442\u0435 4 \u0437\u0430\u043D\u044F\u0442\u0438\u0439 \u2013 \u0441\u043A\u0438\u0434\u043A\u0430 5%, 8 \u0437\u0430\u043D\u044F\u0442\u0438\u0439 \u2013 10%.</p><p><em>\u0418\u0433\u0440\u0430 \u0432 \u0433\u043B\u0438\u043D\u0443 - \u0433\u0440\u0443\u043F\u043F\u044B \u0434\u043E 12 \u0447\u0435\u043B. (\u0434\u043B\u044F \u0434\u0435\u0442\u0435\u0439 3-6 \u043B\u0435\u0442 \u0438 \u0438\u0445 \u0440\u043E\u0434\u0438\u0442\u0435\u043B\u0435\u0439), \u043F\u043E \u0432\u043E\u0441\u043A\u0440\u0435\u0441\u0435\u043D\u044C\u044F\u043C \u0441 12.00 \u0434\u043E 12.45, \u0437\u0430\u043F\u0438\u0441\u044C \u043F\u043E \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0443:</em></p><p>900 \u0440\u0443\u0431./1\u0430\u043A.\u0447\u0430\u0441 (\u043D\u0430 \u0440\u0435\u0431\u0435\u043D\u043A\u0430+\u0440\u043E\u0434\u0438\u0442\u0435\u043B\u044F), \u043A\u0430\u0436\u0434\u044B\u0439 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A \u0441\u0435\u043C\u0435\u0439\u0441\u0442\u0432\u0430 +500 \u0440\u0443\u0431.</p><p><em>\u0420\u0443\u0447\u043D\u0430\u044F \u043B\u0435\u043F\u043A\u0430 \u0438 \u0434\u0435\u043A\u043E\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043A\u0435\u0440\u0430\u043C\u0438\u043A\u0438 (__\u0437\u0430\u043D\u044F\u0442\u0438\u044F \u0432</em> <em>\u0433\u0440\u0443\u043F\u043F\u0430\u0445 \u0434\u043E 8-\u043C\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A), \u0437\u0430\u043D\u044F\u0442\u0438\u044F \u043F\u0440\u043E\u0432\u043E\u0434\u044F\u0442\u0441\u044F \u043F\u043E \u043C\u0435\u0440\u0435 \u043D\u0430\u0431\u043E\u0440\u0430 \u0433\u0440\u0443\u043F\u043F\u044B, \u0437\u0430\u043F\u0438\u0441\u044C \u043F\u043E \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0443:</em> \u0412\u0437\u0440\u043E\u0441\u043B\u044B\u0435 - 3000 \u0440\u0443\u0431./4 \u0430\u043A.\u0447\u0430\u0441\u0430.<em>\u041B\u0435\u043F\u043A\u0430/\u0433\u043E\u043D\u0447\u0430\u0440\u043D\u043E\u0435 \u0434\u0435\u043B\u043E \u0434\u043B\u044F \u0448\u043A\u043E\u043B\u044C\u043D\u0438\u043A\u043E\u0432 \u0441 \u044D\u043A\u0441\u043A\u0443\u0440\u0441\u0438\u0435\u0439 \u043F\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 (\u0433\u0440\u0443\u043F\u043F\u044B 10-20 \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u0432\u043E\u0437\u0440\u0430\u0441\u0442 7-12 \u043B\u0435\u0442.), \u0437\u0430\u043F\u0438\u0441\u044C \u043F\u043E \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0443:</em> <em>1500 \u0440\u0443\u0431./\u0447\u0435\u043B. \u0437\u0430 2-3 \u0447\u0430\u0441\u0430.</em></p><p><img src="'+o+'" alt=""></p><p><strong>\u041E\u0411\u0416\u0418\u0413</strong></p><p>\u041F\u0435\u0447\u043A\u0430 \xAB\u041C\u0443\u0444\u0430\xBB 60 \u043B\u0438\u0442\u0440\u043E\u0432, 34\u044538\u044554 \u0441\u043C,1200\xB0, \u0434\u0430\u043C\u0430 \u0441\u0442\u0440\u043E\u0433\u0430\u044F \u0441 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u043E\u043C!</p><p>\u0410\u0440\u0435\u043D\u0434\u0430 \u043F\u0435\u0447\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E - 1400 \u0440\u0443\u0431.</p><p>\u0418\u0437\u0434\u0435\u043B\u0438\u044F \xAB\u043D\u0430 \u043F\u043E\u0434\u0441\u0430\u0434\u043A\u0443\xBB - \u043E\u0434\u043D\u043E \u0438\u0437\u0434\u0435\u043B\u0438\u0435 \u0440\u0430\u0437\u043C\u0435\u0440\u043E\u043C &lt; \u0444\u043E\u0440\u043C\u0430\u0442\u0430 \u04105 - \xA0100 \u0440\u0443\u0431.</p><p>\u041F\u043E\u043B\u043A\u0430 (34\u044538 \u0441\u043C) - 500 \u0440\u0443\u0431.</p><p>\u041C\u044B \u0437\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u043C \u0438 \u0440\u0430\u0437\u0433\u0440\u0443\u0436\u0430\u0435\u043C \u0434\u043B\u044F \u0412\u0430\u0441 \u043F\u0435\u0447\u044C \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E!</p><p>\u041F\u0435\u0447\u043A\u0430 \xAB\u041C\u0443\u0444\u0430\xBB \u043C\u043E\u0436\u0435\u0442 \u043E\u0442\u043A\u0430\u0437\u0430\u0442\u044C \u0412\u0430\u043C \u0432 \u043E\u0431\u0436\u0438\u0433\u0435, \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u044B \u043E\u0431\u0436\u0438\u0433\u0430 \u043D\u0435 \u0433\u0430\u0440\u0430\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u044B!</p><p><strong>\u041C\u0415\u0420\u041E\u041F\u0420\u0418\u042F\u0422\u0418\u042F</strong></p><p>\u041C\u044B \u043F\u0440\u043E\u0432\u0435\u0434\u0435\u043C \u0434\u043B\u044F \u0412\u0430\u0441 \u043A\u043E\u0440\u043F\u043E\u0440\u0430\u0442\u0438\u0432, \u0434\u0435\u043D\u044C \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u0441\u0435\u043C\u0435\u0439\u043D\u044B\u0439 \u043F\u0440\u0430\u0437\u0434\u043D\u0438\u043A \u0432 \u043D\u0430\u0448\u0435\u0439 \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u043A\u043E\u0439 \u0438\u043B\u0438 \u043D\u0430 \u0412\u0430\u0448\u0435\u0439 \u0442\u0435\u0440\u0440\u0438\u0442\u043E\u0440\u0438\u0438! \u0421\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u044C \u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u044F \u0440\u0430\u0441\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u043F\u043E \u0437\u0430\u043F\u0440\u043E\u0441\u0443.</p><p><strong>\u0410\u0420\u0415\u041D\u0414\u0410 \u0420\u0410\u0411\u041E\u0427\u0415\u0413\u041E \u041C\u0415\u0421\u0422\u0410</strong></p><p>\u0413\u043E\u043D\u0447\u0430\u0440\u043D\u044B\u0439 \u043A\u0440\u0443\u0433, \u043B\u0435\u043F\u043A\u0430, \u043F\u043E\u043A\u0440\u0430\u0441\u043A\u0430 \u2013 500 \u0440\u0443\u0431./\u0447\u0430\u0441.</p><p>\u041C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u044B \u043E\u043F\u043B\u0430\u0447\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E.</p>',22),_=[a];function c(n,i,m,d,g,l){return e(),t("div",null,_)}var f=p(r,[["render",c]]);export{T as __pageData,f as default};
